#include <vector>
#include <queue>
#include <set>
#include <iostream>
using namespace std;

long long solve(vector<long long> nums) {
    const int MAX = 1000000;

    struct Precompute {
        vector<int> spf;
        vector<bool> is_prime;
        Precompute() {
            spf.resize(MAX + 1);
            is_prime.resize(MAX + 1, false);
            for (int i = 0; i <= MAX; i++) {
                spf[i] = i;
            }
            is_prime[0] = false;
            is_prime[1] = false;
            for (int i = 2; i <= MAX; i++) {
                if (spf[i] == i) {
                    is_prime[i] = true;
                    for (long long j = (long long)i * 2; j <= MAX; j += i) {
                        if (spf[j] == j) {
                            spf[j] = i;
                        }
                    }
                }
            }
        }
    };

    static Precompute pc;

    int n = nums.size();
    vector<int> dist(n, -1);

    vector<bool> appear_prime(MAX + 1, false);
    for (long long num : nums) {
        if (num > 1 && num <= MAX) {
            if (pc.is_prime[num]) {
                appear_prime[num] = true;
            }
        }
    }

    vector<vector<int>> groups(MAX + 1);

    for (int j = 0; j < n; j++) {
        long long x = nums[j];
        if (x == 1) continue;

        set<int> distinct_primes;
        long long temp = x;
        while (temp > 1) {
            int p = pc.spf[temp];
            distinct_primes.insert(p);
            while (temp % p == 0) {
                temp /= p;
            }
        }

        for (int p : distinct_primes) {
            if (p <= MAX && appear_prime[p]) {
                groups[p].push_back(j);
            }
        }
    }

    vector<bool> prime_used(MAX + 1, false);
    queue<int> q;
    dist[0] = 0;
    q.push(0);

    while (!q.empty()) {
        int u = q.front(); q.pop();
        if (u == n - 1) {
            return dist[u];
        }

        if (u - 1 >= 0 && dist[u - 1] == -1) {
            dist[u - 1] = dist[u] + 1;
            q.push(u - 1);
        }
        if (u + 1 < n && dist[u + 1] == -1) {
            dist[u + 1] = dist[u] + 1;
            q.push(u + 1);
        }

        long long val = nums[u];
        if (val > 1 && val <= MAX && pc.is_prime[val]) {
            if (!prime_used[val]) {
                prime_used[val] = true;
                for (int j_index : groups[val]) {
                    if (j_index == u) continue;
                    if (dist[j_index] == -1) {
                        dist[j_index] = dist[u] + 1;
                        q.push(j_index);
                    }
                }
            }
        }
    }

    return dist[n - 1];
}
