        spf[i] = i;
    for (int i = 2; i * i <= MAXV; i++) {
        if (spf[i] == i) {
            for (int j = i * i; j <= MAXV; j += i) {
                if (spf[j] == j)
                    spf[j] = i;
            }
        }
    }
    for (int i = 2; i <= MAXV; i++)
        is_prime[i] = (spf[i] == i);
}

