        return 0;

    buildSieve();
    int n = nums.size();
    vector<vector<int>> factors(n);
    for (int j = 0; j < n; j++) {
        int x = static_cast<int>(nums[j]);
        if (x == 1) 
            continue;
        int temp = x;
        while (temp > 1) {
            int p = spf[temp];
            factors[j].push_back(p);
            while (temp % p == 0)
                temp /= p;
        }
    }

    map<int, set<int>> sets_by_prime;
    for (int j = 0; j < n; j++) {
        for (int p : factors[j]) {
            sets_by_prime[p].insert(j);
        }
    }

    vector<long long> dist(n, -1);
    queue<int> q;
    dist[0] = 0;
    for (int p : factors[0]) {
        if (sets_by_prime.find(p) != sets_by_prime.end()) {
            if (sets_by_prime[p].count(0)) {
                sets_by_prime[p].erase(0);
            }
        }
    }
    q.push(0);

    while (!q.empty()) {
        int i = q.front(); 
        q.pop();

        if (i == n - 1) {
            break;
        }

        if (i - 1 >= 0 && dist[i - 1] == -1) {
            dist[i - 1] = dist[i] + 1;
            for (int p : factors[i - 1]) {
                if (sets_by_prime.find(p) != sets_by_prime.end()) {
                    if (sets_by_prime[p].count(i - 1)) {
                        sets_by_prime[p].erase(i - 1);
                    }
                }
            }
            q.push(i - 1);
        }
        if (i + 1 < n && dist[i + 1] == -1) {
            dist[i + 1] = dist[i] + 1;
            for (int p : factors[i + 1]) {
                if (sets_by_prime.find(p) != sets_by_prime.end()) {
                    if (sets_by_prime[p].count(i + 1)) {
                        sets_by_prime[p].erase(i + 1);
                    }
                }
            }
            q.push(i + 1);
        }

        int num = static_cast<int>(nums[i]);
        if (num >= 2 && num <= MAXV && is_prime[num]) {
            int p0 = num;
            if (sets_by_prime.find(p0) != sets_by_prime.end()) {
                auto& s = sets_by_prime[p0];
                while (!s.empty()) {
                    int j = *(s.begin());
                    s.erase(s.begin());
                    if (dist[j] != -1)
                        continue;
                    for (int p : factors[j]) {
                        if (p == p0)
                            continue;
                        if (sets_by_prime.find(p) != sets_by_prime.end() && sets_by_prime[p].count(j)) {
                            sets_by_prime[p].erase(j);
                        }
                    }
                    dist[j] = dist[i] + 1;
                    q.push(j);
                }
            }
        }
    }

    return dist[n - 1];
}
